pub(crate) fn buffered_event_to_typed(
    py: Python<'_>,
    event: &BufferedEvent,
) -> PyResult<Py<PyAny>> {
    match event {
        BufferedEvent::Connected => Py::new(py, Connected)
            .map(|p| p.into_any()),
        BufferedEvent::ContractAssigned {
            id,
            contract,
        } => {
            let contract_py = Py::new(py, ContractRef::from_core(contract))?;
            Py::new(
                py,
                ContractAssigned {
                    id: *id,
                    contract: contract_py.clone_ref(py),
                },
            )
            .map(|p| p.into_any())
        }
        BufferedEvent::Disconnected {
            reason,
        } => Py::new(
            py,
            Disconnected {
                reason: *reason,
            },
        )
        .map(|p| p.into_any()),
        BufferedEvent::Error {
            message,
        } => Py::new(
            py,
            Error {
                message: message.clone(),
            },
        )
        .map(|p| p.into_any()),
        BufferedEvent::LoginSuccess {
            permissions,
        } => Py::new(
            py,
            LoginSuccess {
                permissions: permissions.clone(),
            },
        )
        .map(|p| p.into_any()),
        BufferedEvent::MarketClose => Py::new(py, MarketClose)
            .map(|p| p.into_any()),
        BufferedEvent::MarketOpen => Py::new(py, MarketOpen)
            .map(|p| p.into_any()),
        BufferedEvent::Ohlcvc {
            contract,
            ms_of_day,
            open,
            high,
            low,
            close,
            volume,
            count,
            date,
            received_at_ns,
        } => {
            let contract_py = Py::new(py, ContractRef::from_core(contract))?;
            Py::new(
                py,
                Ohlcvc {
                    contract: contract_py.clone_ref(py),
                    ms_of_day: *ms_of_day,
                    open: *open,
                    high: *high,
                    low: *low,
                    close: *close,
                    volume: *volume,
                    count: *count,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any())
        }
        BufferedEvent::OpenInterest {
            contract,
            ms_of_day,
            open_interest,
            date,
            received_at_ns,
        } => {
            let contract_py = Py::new(py, ContractRef::from_core(contract))?;
            Py::new(
                py,
                OpenInterest {
                    contract: contract_py.clone_ref(py),
                    ms_of_day: *ms_of_day,
                    open_interest: *open_interest,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any())
        }
        BufferedEvent::Ping {
            payload,
        } => Py::new(
            py,
            Ping {
                payload: payload.clone(),
            },
        )
        .map(|p| p.into_any()),
        BufferedEvent::Quote {
            contract,
            ms_of_day,
            bid_size,
            bid_exchange,
            bid,
            bid_condition,
            ask_size,
            ask_exchange,
            ask,
            ask_condition,
            date,
            received_at_ns,
        } => {
            let contract_py = Py::new(py, ContractRef::from_core(contract))?;
            Py::new(
                py,
                Quote {
                    contract: contract_py.clone_ref(py),
                    ms_of_day: *ms_of_day,
                    bid_size: *bid_size,
                    bid_exchange: *bid_exchange,
                    bid: *bid,
                    bid_condition: *bid_condition,
                    ask_size: *ask_size,
                    ask_exchange: *ask_exchange,
                    ask: *ask,
                    ask_condition: *ask_condition,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any())
        }
        BufferedEvent::Reconnected => Py::new(py, Reconnected)
            .map(|p| p.into_any()),
        BufferedEvent::ReconnectedServer => Py::new(py, ReconnectedServer)
            .map(|p| p.into_any()),
        BufferedEvent::Reconnecting {
            reason,
            attempt,
            delay_ms,
        } => Py::new(
            py,
            Reconnecting {
                reason: *reason,
                attempt: *attempt,
                delay_ms: *delay_ms,
            },
        )
        .map(|p| p.into_any()),
        BufferedEvent::ReqResponse {
            req_id,
            result,
        } => Py::new(
            py,
            ReqResponse {
                req_id: *req_id,
                result: *result,
            },
        )
        .map(|p| p.into_any()),
        BufferedEvent::Restart => Py::new(py, Restart)
            .map(|p| p.into_any()),
        BufferedEvent::ServerError {
            message,
        } => Py::new(
            py,
            ServerError {
                message: message.clone(),
            },
        )
        .map(|p| p.into_any()),
        BufferedEvent::Trade {
            contract,
            ms_of_day,
            sequence,
            ext_condition1,
            ext_condition2,
            ext_condition3,
            ext_condition4,
            condition,
            size,
            exchange,
            price,
            condition_flags,
            price_flags,
            volume_type,
            records_back,
            date,
            received_at_ns,
        } => {
            let contract_py = Py::new(py, ContractRef::from_core(contract))?;
            Py::new(
                py,
                Trade {
                    contract: contract_py.clone_ref(py),
                    ms_of_day: *ms_of_day,
                    sequence: *sequence,
                    ext_condition1: *ext_condition1,
                    ext_condition2: *ext_condition2,
                    ext_condition3: *ext_condition3,
                    ext_condition4: *ext_condition4,
                    condition: *condition,
                    size: *size,
                    exchange: *exchange,
                    price: *price,
                    condition_flags: *condition_flags,
                    price_flags: *price_flags,
                    volume_type: *volume_type,
                    records_back: *records_back,
                    date: *date,
                    received_at_ns: *received_at_ns,
                },
            )
            .map(|p| p.into_any())
        }
        BufferedEvent::UnknownControl => Py::new(py, UnknownControl)
            .map(|p| p.into_any()),
        BufferedEvent::UnknownFrame {
            code,
            payload,
        } => Py::new(
            py,
            UnknownFrame {
                code: *code,
                payload: payload.clone(),
            },
        )
        .map(|p| p.into_any()),
    }
}

pub(crate) fn register_fpss_event_classes(m: &Bound<'_, PyModule>) -> PyResult<()> {
    m.add_class::<ContractRef>()?;
    m.add_class::<Connected>()?;
    m.add_class::<ContractAssigned>()?;
    m.add_class::<Disconnected>()?;
    m.add_class::<Error>()?;
    m.add_class::<LoginSuccess>()?;
    m.add_class::<MarketClose>()?;
    m.add_class::<MarketOpen>()?;
    m.add_class::<Ohlcvc>()?;
    m.add_class::<OpenInterest>()?;
    m.add_class::<Ping>()?;
    m.add_class::<Quote>()?;
    m.add_class::<Reconnected>()?;
    m.add_class::<ReconnectedServer>()?;
    m.add_class::<Reconnecting>()?;
    m.add_class::<ReqResponse>()?;
    m.add_class::<Restart>()?;
    m.add_class::<ServerError>()?;
    m.add_class::<Trade>()?;
    m.add_class::<UnknownControl>()?;
    m.add_class::<UnknownFrame>()?;
    Ok(())
}
